const response = $.steps.exaSearch.response || {};
const data = response.data || response;
const results = data.results || [];

let context = '';
const sources = [];

results.slice(0, 8).forEach((r, i) => {
  const title = r.title || 'Result ' + (i + 1);
  const url = r.url || '';
  const text = (r.text || r.snippet || '').slice(0, 1500);
  context += 'SOURCE ' + (i + 1) + ': ' + title + '\n';
  context += 'URL: ' + url + '\n';
  context += text + '\n\n';
  sources.push({ title, url });
});

return { context, sources, resultCount: results.length };

const question = $.input.question;
const ctx = $.steps.compileResults.output;

let prompt = 'You are a helpful AI chatbot with web search capabilities. Answer the user\'s question using the web search results provided. Be conversational, accurate, and cite your sources.\n\n';
prompt += 'USER QUESTION: ' + question + '\n\n';
prompt += 'WEB SEARCH RESULTS:\n' + ctx.context + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer conversationally but accurately\n';
prompt += '- Reference source numbers when citing information\n';
prompt += '- If the search results don\'t fully answer the question, acknowledge gaps\n';
prompt += '- Keep the answer concise (150-300 words)\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "your conversational answer with [Source N] citations",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "topSources": [1, 2],\n';
prompt += '  "relatedTopics": ["topic1", "topic2"]\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'unknown', topSources: [], relatedTopics: [] }; }

const ai = $.steps.parseAI.output;
const ctx = $.steps.compileResults.output;
const question = $.input.question;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Web Search Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + question } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Sources Found:*\n' + ctx.resultCount },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') }
] });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });

if (ctx.sources && ctx.sources.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources:*\n';
  ctx.sources.slice(0, 5).forEach((s, i) => {
    srcText += (i + 1) + '. <' + s.url + '|' + (s.title || 'Source') + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}

if (ai.relatedTopics && ai.relatedTopics.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '*Related:* ' + ai.relatedTopics.slice(0, 4).join(' | ') }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI' }] });

const fallbackText = 'Web Search: ' + question.slice(0, 50) + ' - ' + (ai.answer || '').slice(0, 100);
return { blocks, fallbackText };
